    def generate_qr_code_ascii(self, secret, user_email, issuer='MFASystem'):
        """
        Generate an ASCII art QR code for terminal display.

        Args:
            secret: Base32-encoded secret
            user_email: User's email or identifier
            issuer: Service name/issuer

        Returns:
            ASCII string representation of QR code
        """
        if not HAS_QRCODE:
            raise ImportError(
                "qrcode library is required. Install with: pip install qrcode"
            )

        uri = self.get_provisioning_uri(secret, user_email, issuer)

        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=1,
            border=1,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        # Build ASCII representation
        lines = []
        for row in qr.modules:
            line = ''
            for cell in row:
                line += '██' if cell else '  '
            lines.append(line)

        return '\n'.join(lines)

