def interactive_mode():
    """Run an interactive TOTP MFA session."""
    auth = TOTPAuthenticator()

    print("\n" + "=" * 60)
    print("  Interactive TOTP MFA System")
    print("=" * 60)

    while True:
        print("\nOptions:")
        print("  1. Register new user")
        print("  2. Verify registration")
        print("  3. Authenticate user")
        print("  4. Generate current code (for testing)")
        print("  5. Show user info")
        print("  6. Reset user MFA")
        print("  7. Exit")

        choice = input("\nSelect option (1-7): ").strip()

        if choice == '1':
            user_id = input("Enter user ID: ").strip()
            email = input("Enter email: ").strip()
            issuer = input("Enter issuer (default: MFASystem): ").strip() or "MFASystem"

            try:
                result = auth.register_user(user_id, email, issuer)
                print(f"\n✓ User registered!")
                print(f"  Secret: {result['secret']}")
                print(f"  URI: {result['provisioning_uri']}")
                print(f"  Backup codes: {result['backup_codes']}")

                if HAS_QRCODE:
                    try:
                        ascii_qr = auth.generate_qr_code_ascii(
                            result['secret'], email, issuer
                        )
                        print(f"\n  QR Code:")
                        for line in ascii_qr.split('\n'):
                            print(f"  {line}")
                    except Exception:
                        pass

                print(f"\n  Please verify with a code from your authenticator app.")
            except Exception as e:
                print(f"✗ Error: {e}")

        elif choice == '2':
            user_id = input("Enter user ID: ").strip()
            code = input("Enter TOTP code: ").strip()

            try:
                if auth.confirm_registration(user_id, code):
                    print("✓ Registration verified successfully!")
                else:
                    print("✗ Invalid code. Please try again.")
            except ValueError as e:
                print(f"✗ Error: {e}")

        elif choice == '3':
            user_id = input("Enter user ID: ").strip()
            code = input("Enter TOTP or backup code: ").strip()

            result = auth.authenticate_user(user_id, code)
            if result['authenticated']:
                print(f"✓ Authentication successful! (method: {result['method']})")
                if result['method'] == 'backup_code':
                    print(f"  Remaining backup codes: {result['remaining_backup_codes']}")
            else:
                print(f"✗ Authentication failed: {result['error']}")

        elif choice == '4':
            user_id = input("Enter user ID: ").strip()
            if user_id in auth._users_db:
                secret = auth._users_db[user_id]['secret']
                code = auth.generate_totp(secret)
                remaining = get_remaining_seconds()
                print(f"  Current code: {code} (expires in {remaining}s)")
            else:
                print(f"✗ User not found")

        elif choice == '5':
            user_id = input("Enter user ID: ").strip()
            info = auth.get_user_info(user_id)
            if info:
                print("\n  User Info:")
                for key, value in info.items():
                    print(f"    {key}: {value}")
            else:
                print("✗ User not found")

        elif choice == '6':
            user_id = input("Enter user ID: ").strip()
            try:
                result = auth.reset_user_mfa(user_id)
                print(f"✓ MFA reset! New secret: {result['secret']}")
                print(f"  New backup codes: {result['backup_codes']}")
            except ValueError as e:
                print(f"✗ Error: {e}")

        elif choice == '7':
            print("\nGoodbye!")
            break

        else:
            print("Invalid option.")


